firmware_template.source:
#include "i2s_microphone.h"
#include <driver/i2s.h>
#include <math.h>

// S3-PRO default pins — override via Parakram app
#define I2S_WS  4
#define I2S_SCK 5
#define I2S_SD  7
#define SAMPLE_RATE 16000
#define FRAME_SIZE  256

static int16_t _sample = 0;
static float _db = 0;
static float _rms = 0;
static int32_t _hpf_in = 0, _hpf_out = 0;

static int16_t _process(int32_t raw) {
    int32_t v = raw >> 11;
    if (v > 30000) v = 30000;
    if (v < -30000) v = -30000;
    int32_t s = (int16_t)v;
    int32_t d = s - _hpf_in;
    int32_t o = (_hpf_out * 31785 + d * 31785) >> 15;
    if (o > 32767) o = 32767;
    if (o < -32768) o = -32768;
    _hpf_in = s; _hpf_out = o;
    return (int16_t)o;
}

void i2s_mic_setup() {
    i2s_config_t cfg = {};
    cfg.mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_RX);
    cfg.sample_rate = SAMPLE_RATE;
    cfg.bits_per_sample = I2S_BITS_PER_SAMPLE_32BIT;
    cfg.channel_format = I2S_CHANNEL_FMT_ONLY_LEFT;
    cfg.communication_format = I2S_COMM_FORMAT_STAND_I2S;
    cfg.intr_alloc_flags = ESP_INTR_FLAG_LEVEL1;
    cfg.dma_buf_count = 8;
    cfg.dma_buf_len = FRAME_SIZE;
    cfg.use_apll = true;
    i2s_driver_install(I2S_NUM_0, &cfg, 0, NULL);
    i2s_pin_config_t pins = { .bck_io_num = I2S_SCK, .ws_io_num = I2S_WS, .data_out_num = -1, .data_in_num = I2S_SD };
    i2s_set_pin(I2S_NUM_0, &pins);
    i2s_zero_dma_buffer(I2S_NUM_0);
    Serial.println("[i2s_mic] INMP441 OK 16kHz");
}

void i2s_mic_loop() {
    int32_t buf[FRAME_SIZE];
    size_t rd = 0;
    i2s_read(I2S_NUM_0, buf, sizeof(buf), &rd, portMAX_DELAY);
    int n = rd / 4;
    if (n <= 0) return;
    double sum = 0;
    for (int i = 0; i < n; i++) {
        int16_t s = _process(buf[i]);
        double d = (double)s / 32768.0;
        sum += d * d;
        _sample = s;
    }
    _rms = (float)sqrt(sum / n);
    _db = (_rms > 0) ? 20.0f * log10f(_rms) + 94.0f : 0;
}

int16_t i2s_mic_get_sample() { return _sample; }
float i2s_mic_get_db() { return _db; }
float i2s_mic_get_rms() { return _rms; }
